function t(){const e=document.getElementById("dark-mode-toggle");if(!e)return;(localStorage.getItem("darkMode")==="true"||!localStorage.getItem("darkMode")&&window.matchMedia("(prefers-color-scheme: dark)").matches)&&document.documentElement.classList.add("dark"),e.addEventListener("click",()=>{document.documentElement.classList.toggle("dark"),localStorage.setItem("darkMode",document.documentElement.classList.contains("dark").toString())})}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",t):t();
